def score_gain(gain, min_gain):
    """增益评分 (越大越好)"""
    if math.isnan(gain):
        return 0.0

    threshold = abs(min_gain) * 0.9  # 用差值判断严重不足
    if gain < min_gain - threshold:
        return 0.0
    elif gain < min_gain:
        ratio = (gain - (min_gain - threshold)) / threshold
        return ratio ** 2
    else:
        return 1.0


